import{_ as t,o,c as a,a0 as d}from"./chunks/framework.RZHxwcNF.js";const r="/images/hub_proposal.png",s="/images/hub_proposal_create.png",j=JSON.parse('{"title":"Projects","description":"","frontmatter":{},"headers":[],"relativePath":"guide/user/projects.md","filePath":"guide/user/projects.md"}'),i={name:"guide/user/projects.md"};function n(c,e,p,l,h,u){return o(),a("div",null,[...e[0]||(e[0]=[d('<h1 id="projects" tabindex="-1">Projects <a class="header-anchor" href="#projects" aria-label="Permalink to &quot;Projects&quot;">​</a></h1><p>Projects are collaborative research units in FLAME Hub. They group analyses, nodes, and data requirements into a single organizational context.</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p><img src="'+r+'" alt="Projects overview"></p><h2 id="creating-a-project" tabindex="-1">Creating a Project <a class="header-anchor" href="#creating-a-project" aria-label="Permalink to &quot;Creating a Project&quot;">​</a></h2><p><img src="'+s+'" alt="Create project"></p><p>A project defines:</p><ul><li><strong>Name</strong> and description</li><li><strong>Selected nodes</strong> — the institutions participating in the analysis</li><li><strong>Risk assessment</strong> — evaluation of data sensitivity and privacy requirements</li></ul><h3 id="naming" tabindex="-1">Naming <a class="header-anchor" href="#naming" aria-label="Permalink to &quot;Naming&quot;">​</a></h3><p>Like analyses, projects have two name fields:</p><ul><li><strong><code>name</code></strong> — a unique, URL-friendly identifier (lowercase letters, digits and the characters <code>-</code>, <code>_</code>, <code>.</code>; no whitespace). It is <strong>required</strong> and must be unique. If you do not provide one when creating a project, a readable name is <strong>generated automatically</strong> (e.g. <code>brave-otter-1a2b3c</code>); the create form also pre-fills an editable suggestion.</li><li><strong><code>display_name</code></strong> — an optional, free-form human-readable label. When set, it is shown in the UI in place of the <code>name</code>.</li></ul><p>Once created, a project enters a pending state and requires <a href="/guide/user/approval.html">administrator approval</a> before analyses can be added (unless approval is disabled in development).</p><h2 id="project-nodes" tabindex="-1">Project Nodes <a class="header-anchor" href="#project-nodes" aria-label="Permalink to &quot;Project Nodes&quot;">​</a></h2><p>Nodes are assigned to projects via <code>ProjectNode</code> associations. Only nodes assigned to a project can participate in that project&#39;s analyses.</p><h2 id="api-endpoints" tabindex="-1">API Endpoints <a class="header-anchor" href="#api-endpoints" aria-label="Permalink to &quot;API Endpoints&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Method</th><th>Endpoint</th><th>Description</th></tr></thead><tbody><tr><td><code>GET</code></td><td><code>/projects</code></td><td>List projects</td></tr><tr><td><code>POST</code></td><td><code>/projects</code></td><td>Create project</td></tr><tr><td><code>GET</code></td><td><code>/projects/:id</code></td><td>Get project details</td></tr><tr><td><code>PUT</code></td><td><code>/projects/:id</code></td><td>Update project</td></tr><tr><td><code>DELETE</code></td><td><code>/projects/:id</code></td><td>Delete project</td></tr><tr><td><code>GET</code></td><td><code>/project-nodes</code></td><td>List project-node associations</td></tr><tr><td><code>POST</code></td><td><code>/project-nodes</code></td><td>Assign node to project</td></tr><tr><td><code>DELETE</code></td><td><code>/project-nodes/:id</code></td><td>Remove node from project</td></tr></tbody></table>',16)])])}const m=t(i,[["render",n]]);export{j as __pageData,m as default};
